export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i += 1
    } else if (arg.includes('=')) {
      const key = arg.slice(2, -1)
      const value = arg.slice(-1)
      result[key] = value
      i += 1
    } else {
      result[arg.slice(2)] = true
      i += 1
    }
  }
  return result
}

